}

**
* 새로운 게시글이 있는지 체크하여 세션에 주입하는 메서드
* @param request
*/
private void checkUpToDateContents(HttpServletRequest request) {
        SessionHelper.setSessionDataInNewContents(request.getSession(), boardService.getUpToDateContents());
}
